}"}, {"path": "src/store.ts", "content": "import fs from 'node:fs';
import crypto from 'node:crypto';

interface Task {
  id: string;
  title: string;
  done: boolean;
  createdAt: string;
  doneAt?: string;
}

export class TaskStore {
  private filePath: string;

  constructor(filePath: string) {
    this.filePath = filePath;
    if (!fs.existsSync(filePath)) {
      fs.writeFileSync(filePath, JSON.stringify({ tasks: [] }));
    }
  }

  list(): Task[] {
    const data = fs.readFileSync(this.filePath, 'utf-8');
    return JSON.parse(data).tasks;
  }

  add(title: string): Task {
    const tasks = this.list();
    const task = { id: crypto.randomUUID(), title, done: false, createdAt: new Date().toISOString() };
    tasks.push(task);
    fs.writeFileSync(this.filePath, JSON.stringify({ tasks }));
    return task;
  }

  done(id: string): Task | undefined {
    const tasks = this.list();
    const task = tasks.find(t => t.id === id);
    if (task) {
      task.done = true;
      task.doneAt = new Date().toISOString();
      fs.writeFileSync(this.filePath, JSON.stringify({ tasks }));
    }
    return task;
  }

  remove(id: string): boolean {
    let tasks = this.list();
    tasks = tasks.filter(t => t.id !== id);
    fs.writeFileSync(this.filePath, JSON.stringify({ tasks }));
    return true;
  }
}
"}, {"path": "src/cli.ts", "content": "import { TaskStore } from './store';
import fs from 'node:fs';
import readline from 'node:readline';

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

function prompt(question: string): Promise<string> {
  return new Promise(resolve => {
    rl.question(question, resolve);
  });
}

async function main() {
  const filePath = await prompt('Enter the data file path: ');
  const taskStore = new TaskStore(filePath);

  while (true) {
    const command = await prompt('Enter a command (add, list, done, remove, exit): ');

    switch (command) {
      case 'add':
        const title = await prompt('Enter the task title: ');
        taskStore.add(title);
        console.log('Task added.');
        break;
      case 'list':
        console.log(taskStore.list());
        break;
      case 'done':
        const id = await prompt('Enter the task id: ');
        const task = taskStore.done(id);
        if (task) {
          console.log('Task marked as done:', task);
        } else {
          console.log('Task not found.');
        }
        break;
      case 'remove':
        const taskId = await prompt('Enter the task id: ');
        const success = taskStore.remove(taskId);
        if (success) {
          console.log('Task removed.');
        } else {
          console.log('Task not found.');
        }
        break;
      case 'exit':
        rl.close();
        return;
      default:
        console.log('Unknown command.');
    }
  }
}

main();
